test_cases.python_test_script:
def test_tc_gw_wake_001_message_on_ignition_on(can_bus):
    msgs = collect_messages(can_bus, GW_OPERATIONAL_PRESENCE_ID, 3)
    assert msgs

def test_tc_gw_wake_002_gateway_status_active(can_bus):
    msgs = collect_messages(can_bus, GW_OPERATIONAL_PRESENCE_ID, 2)
    assert msgs
    for msg in msgs:
        assert decode_gateway_status(msg) == 1

def test_tc_gw_wake_003_alive_counter_increment(can_bus):
    msgs = collect_messages(can_bus, GW_OPERATIONAL_PRESENCE_ID, 3)
    assert len(msgs) >= 2
    for i in range(1, len(msgs)):
        assert (decode_alive_counter(msgs[i]) - decode_alive_counter(msgs[i - 1])) % 256 == 1

def test_tc_gw_wake_004_no_message_when_ignition_off(can_bus):
    msgs = collect_messages(can_bus, GW_OPERATIONAL_PRESENCE_ID, 2)
    assert msgs == []

def test_tc_gw_wake_005_immediate_transmission(can_bus):
    msgs = collect_messages(can_bus, GW_OPERATIONAL_PRESENCE_ID, 1)
    assert msgs

def test_tc_gw_wake_006_dlc_check(can_bus):
    msgs = collect_messages(can_bus, GW_OPERATIONAL_PRESENCE_ID, 2)
    assert msgs
    for msg in msgs:
        assert msg.dlc == GW_OPERATIONAL_PRESENCE_DLC
